import math
import time

def dr(n):
    return (n - 1) % 9 + 1

def digsum(n):
    return sum(map(int, list(str(n))))

def persist(n):
    m = n
    ans = 1
    while True:
        x = digsum(m)
        if x < 10:
            return ans
        ans += 1
        m = x

def bad_ones(n):
    # take advantage of the repeating nature of dig_root
    #  and that d(ab) == d(d(a)d(b))
    ndiv9, nmod9 = n // 9, n % 9
    if nmod9 == 0:
        drs = [ndiv9] * 10
    else:
        drs = [ndiv9 + 1] * (nmod9 + 1)  + [ndiv9] * (9 - nmod9)
    answer = sum(drs[i] * drs[j] * drs[dr(i * j)]
                 for j in range(1, 10)
                 for i in range(1, 10))
    answer -= sum(n // i for i in range(1, n + 1))
    return answer

if __name__ == '__main__':
    print(bad_ones(int(input().strip())))

