vector<vector<ll>> connection;
ll N, M, K;
vector<ll> dist;
vector<pll> edges;

vector<string> ans;
void dfs(string& stat, vector<bool>& already, ll index) {
  if (ans.size() == K) {
    return;
  }
  if (index == M) {
    ll cnt = 0;
    for (ll i = 0; i < M; ++i) {
      if (stat.at(i) == '1') {
        cnt += 1;
      }
    }
    if (cnt == N - 1) {
      ans.push_back(stat);
    }
    return;
  }
  ll u = edges.at(index).first, v = edges.at(index).second;
  dfs(stat, already, index + 1);
  if (!already.at(v)) {
    if (dist.at(u) + 1 == dist.at(v)) {
      already.at(v) = true;
      stat.at(index) = '1';
      dfs(stat, already, index + 1);
      already.at(v) = false;
      stat.at(index) = '0';
    }
  }
  if (!already.at(u)) {
    if (dist.at(v) + 1 == dist.at(u)) {
      already.at(u) = true;
      stat.at(index) = '1';
      dfs(stat, already, index + 1);
      already.at(u) = false;
      stat.at(index) = '0';
    }
  }
}

int main() {
  ios::sync_with_stdio(false);
  cin.tie(nullptr);
  cin >> N >> M >> K;
  map<pll, ll> mp;
  connection = vector<vector<ll>>(N);
  for (ll i = 0; i < M; ++i) {
    ll u, v;
    cin >> u >> v;
    u -= 1, v -= 1;
    connection.at(u).push_back(v);
    connection.at(v).push_back(u);
    edges.push_back({u, v});
    mp[{u, v}] = i;
    mp[{v, u}] = i;
  }
  dist = vector<ll>(N, INF);
  dist.at(0) = 0;
  queue<ll> q;
  q.push(0);
  while (!q.empty()) {
    ll now = q.front();
    q.pop();
    for (ll i = 0; i < connection.at(now).size(); ++i) {
      ll next = connection.at(now).at(i);
      if (dist.at(next) > dist.at(now) + 1) {
        q.push(next);
        dist.at(next) = dist.at(now) + 1;
      }
    }
  }
  string s = "";
  for (ll i = 0; i < M; ++i) {
    s += '0';
  }
  vector<bool> already(N, false);
  already.at(0) = true;
  dfs(s, already, 0);
  cout << min(K, (ll)ans.size()) << "\n";
  for (ll i = 0; i < min(K, (ll)ans.size()); ++i) {
    cout << ans.at(i) << "\n";
  }
}

