from heapq import *

class elem:
    def __init__(self,value,counted):
        self.value=value
        self.count=counted
        self.selected=0

    def test_Next(self):
        return self.count/(self.selected+1)
    def take1(self):
        self.selected=self.selected+1
    def __lt__(self,other):
        return self.test_Next()>other.test_Next()
def main():
    global n,k,a
    n,k=[int(x) for x in stdin.readline().split()]
    a=[int(x) for x in stdin.readline().split()]
    if (k*2>n):
        stdout.write(" ".join([str(x) for x in a[:k]]))
        return 0
    count=dict()
    for x in a:
        count[x]=count.get(x,0)+1
    s=[]
    for ky,v in count.items():
        s.append(elem(ky,v))
    heapify(s)
    res=[]
    for i in range(k):
        maxNext=heappop(s)
        maxNext.take1()
        res.append(str(maxNext.value))
        heappush(s,maxNext)
    stdout.write(" ".join(res))
    return 0

