class Window:
    def __init__(self, ones, zeros):
        self.ones = ones
        self.zeros = zeros

    def add(self, x):
        if x:
            self.ones += 1
        else:
            self.zeros += 1

    def remove(self, x):
        if x:
            self.ones -= 1
        else:
            self.zeros -= 1

    def __len__(self):
        return self.zeros + self.ones

    def parity(self):
        if not self.zeros:
            return 1
        if not self.ones:
            return 0
        return -1


