class seg:
    def __init__(self,n):
        self.m = 1
        while self.m < n: self.m *= 2
        self.data = [0]*(2*self.m)
    def add(self, ind, val):
        ind += self.m
        while ind:
            self.data[ind] += val
            ind >>= 1

    def summa(self, l, r):
        l += self.m
        r += self.m
        s = 0
        while l<r:
            if l&1:
                s += self.data[l]
                l += 1
            if r&1:
                r -= 1
                s += self.data[r]
            l >>= 1
            r >>= 1
        return s

