def matpow(mat, n):
    if n==1: return mat
    if n%2: return matmul(mat, matpow(matmul(mat, mat), n/2))
    return matpow(matmul(mat, mat), n/2)

def divisors(n):
    factors = {}
    nn = n
    i = 2
    while i*i <= nn:
        while nn % i == 0:
            if not i in factors:
                factors[i] = 0
            factors[i] += 1
            nn //= i
        i += 1
    if nn > 1:
        factors[nn] = 1
    return factors

