def lps(s):
    p = [0] * len(s)
    i, j = 1, 0
    while i < len(s):
        if s[i] == s[j]:
            j += 1
            p[i] = j
            i += 1
        else:
            if j != 0:
                j = p[j - 1]
            else:
                i += 1

    return p


def kmp(s1, s2, p):
    i, j = 0, 0

    m = [0] * len(s1)

    while i < len(s1):
        if s1[i] == s2[j]:
            j += 1
            m[i] = j
            i += 1

        if j == len(s2):
            j = p[j - 1]
        elif i < len(s1) and s1[i] != s2[j]:
            if j != 0:
                j = p[j - 1]
            else:
                i += 1

    return m


