    n = len(a)
    if n != len(b):
        print(-1, -1)
        return
    a_reversed = a[::-1]
    b_reversed = b[::-1]
    lps_a_reversed = lps(a_reversed)
    lps_b = lps(b)
    last = kmp(b, a_reversed, lps_a_reversed)
    mid = kmp(a, b, lps_b)

    i = 0
    ans = [-1, -1]
    while i < n - 1 and a[i] == b[n - 1 - i]:
        len_last = last[n - 2 - i]
        len_mid = mid[n - 1 - len_last]
        if len_last + len_mid >= n - 1 - i:
            ans = [i, n - len_last]
        i += 1

    print(" ".join(map(str, ans)))


