def nWaysToDivide(field, parts):
    parts.sort()
    i = nCorns = 0

    while nCorns < parts[0]:
        nCorns += sum(field[i])
        i += 1

    if nCorns == parts[0]:
        nCorns = 0
        while nCorns < parts[1]:
            nCorns += sum(field[i])
            i += 1
        if nCorns == parts[1]:
            nWays = {1: 1, 2: 3, 3: 6}[len(set(parts))]
        else:
            nWays = 0

    else:
        nWays = 0

    i = nCorns = 0
    while nCorns < parts[0]:
        nCorns += sum(map(lambda x: x[i], field))
        i += 1

    if nCorns == parts[0]:
        nCorns = 0
        while nCorns < parts[1]:
            nCorns += sum(map(lambda x: x[i], field))
            i += 1
        if nCorns == parts[1]:
            if not nWays:
                return {1: 1, 2: 3, 3: 6}[len(set(parts))]
            return nWays*2
        return nWays

    return nWays


