def real_solve(row, col, k, priority):
  k -= 1
  n = row + col - 1
  cur_string = ['?' for i in range(n)]

  for step in range(row * col):
    min_prior = INF

    for i in range(row):
      for j in range(col):
        min_prior = min(min_prior, priority[i][j])

    r, c = 0, 0
    for i in range(row):
      for j in range(col):
        if min_prior == priority[i][j]:
          r, c = i, j

    idx = (r + c) % n
    priority[r][c] = INF

    if cur_string[idx] != '?':
      continue
    cur_string[idx] = '('
    cnt = count(cur_string)

    if cnt <= k:
      k -= cnt
      cur_string[idx] = ')'

  ans = []
  for i in range(row):
    ans.append(cur_string[i:i+col])

  return ans



