import sys

revmap = {'W': 'S', 'A': 'D', 'S': 'W', 'D': 'A'}

def apply(re, c):
    ct, cr, cd, cl = re
    if c == 'W':
        cd += 1
        ct -= 1
    elif c == 'A':
        cr += 1
        cl -= 1
    elif c == 'S':
        ct += 1
        cd -= 1
    elif c == 'D':
        cl += 1
        cr -= 1
    return max(0, ct), max(0, cr), max(0, cd), max(0, cl)

def compute_prefixes(cmds, rev=False):
    re = [(0, 0, 0, 0)]  # top right down left
    for c in cmds:
        if rev:
            c = revmap[c]
        re.append(apply(re[-1], c))
    return re

def solve(C):
    p1 = compute_prefixes(C)
    p2 = compute_prefixes(C[::-1], rev=True)[::-1]
    areas = []
    for j in xrange(len(p1)):
        for p11 in (p1[j], apply(p1[j], 'W'), apply(p1[j], 'A'), apply(p1[j], 'S'), apply(p1[j], 'D')):
            re = (max(p11[0], p2[j][0]), max(p11[1], p2[j][1]), max(p11[2], p2[j][2]), max(p11[3], p2[j][3]))
            areas.append((re[0] + re[2] + 1) * (re[1] + re[3] + 1))
    return min(areas)

