def solve(N, M):
    def row_count(w):
        dp = [0] * (w + 1)
        dp[0] = 1
        for i in range(w):
            if i + 1 <= w:
                dp[i + 1] += dp[i]
                dp[i + 1] %= MOD
            if i + 2 <= w:
                dp[i + 2] += dp[i]
                dp[i + 2] %= MOD
        return dp[w]

    c = row_count(N)
    r = row_count(M)

    return ((c + r - 1) * 2) % MOD


