class DSU:
    def __init__(self, N):
        self.par = range(N)
        self.rnk = [0] * N

    def find(self, x):
        if self.par[x] != x:
            self.par[x] = self.find(self.par[x])
        return self.par[x]

    def union(self, x, y):
        xr, yr = self.find(x), self.find(y)
        if xr == yr: return False
        if self.rnk[xr] < self.rnk[yr]:
            xr, yr = yr, xr
        if self.rnk[xr] == self.rnk[yr]:
            self.rnk[xr] += 1

        self.par[yr] = xr
        return True


def solve(N, M, graph):
    if N <= 1000:
        # by force
        dsu = DSU(N)

        for u, setv in enumerate(graph):
            for v in xrange(u+1, N):
                if v not in setv:
                    dsu.union(u, v)

        ans = 0
        for u, setv in enumerate(graph):
            for v in setv:
                if dsu.union(u, v):
                    ans += 1
        return ans

    # on average, edge is not there

    # some vertex has at most 100 edges
    u = min(xrange(N), key = lambda i: len(graph[i]))
    # now spread from there
    dsu = DSU(N)
    setv = graph[u]
    for v in xrange(N):
        if v != u and v not in setv:
            dsu.union(u, v)

    # now can brute force.  vertices are setv + u
    for v in setv:
        setw = graph[v]
        for w in xrange(N):
            if w != v and w not in setw:
                dsu.union(v, w)

    ans = 0
    for u, setv in enumerate(graph):
        for v in setv:
            if dsu.union(u, v):
                ans += 1
    return ans


