CANT = "MORTAL"

def solve(R, C, A):
    S = sum(sum(row) for row in A)
    N = R*C
    if S == 0: return CANT
    if S == N: return 0
    # ans is at most 4
    # if any row or col is full, then ans is 1
    B = zip(*A)

    if sum(A[0]) == C or sum(A[-1]) == C:
        return 1
    if sum(B[0]) == R or sum(B[-1]) == R:
        return 1

    # if any corner is A, answer is 2
    if A[0][0] or A[-1][0] or A[0][-1] or A[-1][-1]:
        return 2

    def rindex(lst, x):
        for i in range(len(lst)-1, -1, -1):
            if lst[i] == x:
                return i

    # if any edge can be made whole in one move, ans 2

    for baseline in (A[0], A[-1]):
        c1 = baseline.index(0)
        c2 = rindex(baseline, 0)
        for row in A:
            if all(row[c] for c in range(c1,c2+1)):
                return 2

    for baseline in (B[0], B[-1]):
        r1 = baseline.index(0)
        r2 = rindex(baseline, 0)
        for col in B:
            if all(col[r] for r in range(r1,r2+1)):
                return 2

    # if any edge is, ans is 3
    if any(A[0]) or any(A[-1]) or any(B[0]) or any(B[-1]):
        return 3
    return 4





