		if not visited[u]:

			s = []

			t = []

			dfs(u)



			if len(t) > 0:

				sz = len(t) - 1

				cnt = cntOrder(s, t)



				# Number of orders for current WCC

				ans = (ans * cnt) % MOD

				# Number of ways to insert <sz> number to array of <curLen> elements

				ans = (ans * c[curLen + sz][sz]) % MOD

				curLen += sz		



	print(ans)



