class segtree:
    def __init__(s, n):
        s.m = 1
        while s.m < n: s.m *= 2
        s.data = [0]*(2 * s.m)

    def add(s, i, x):
        i += s.m
        while i:
            s.data[i] += 1
            i >>= 1

    def first(s, l, r):
        l += s.m
        r += s.m

        best = -1
        while l < r:
            if l & 1:
                if s.data[l]:
                    best = l
                    break
                l += 1
            if r & 1:
                r -= 1
                if s.data[r]:
                    best = r
            l >>= 1
            r >>= 1
        if best == -1:
            return -1

        while best < s.m:
            best <<= 1
            if not s.data[best]:
                best += 1
        return best - s.m

