def blocksize( b ):
    if b in bsc:
        return bsc[ b ]
    d = digs( b )
    tp = tenp( d - 1 )
    sz = d * ( b - tp + 1 )
    while d > 1:
        d -= 1
        tp //= 10
        sz += d * tp * 9
    bsc[ b ] = sz
    return sz
def dec( x ):
