class segtree:
    def __init__(self, n):
        m = 1
        while m < n: m *= 2
        self.m = m
        self.data = [0]*(2 * m)

    def add(self, i):
        i += self.m
        while i:
            self.data[i] += 1
            i >>= 1

    def finder(self, l, r):
        m = self.m
        data = self.data
        l += m
        r += m
        cand = []
        while l < r:
            if l & 1:
                if data[l]:
                    cand.append(l)
                l += 1
            if r & 1:
                r -= 1
                if data[r]:
                    cand.append(r)
            l >>= 1
            r >>= 1

        ans = []
        for i in cand:
            while i < m and data[i]:
                if data[2 * i]:
                    cand.append(2 * i)
                i = 2 * i + 1
            if data[i]:
                ans.append(i - m)
        return ans

