def query(L, R):
    # A <= L, B <= R
    # up to 30 bits in each number

    BIG = 30
    bitA = [0] * BIG
    bitB = [0] * BIG
    x=L
    for i in xrange(BIG):
        bitA[i] = x & 1
        x >>= 1
    x=R
    for i in xrange(BIG):
        bitB[i] = x & 1
        x >>= 1

    #print bitA
    #print bitB

    @memo
    def dp(i, aflag=True, bflag=True):
        if i == -1: return 1
        candA = [0, 1]
        candB = [0, 1]
        if aflag and bitA[i] == 0:
            # we cant put 1 if actual is 0
            candA.pop()
        if bflag and bitB[i] == 0:
            candB.pop()
        ans = 0
        #print '!', i, aflag, bflag, candA, candB
        for ca in candA:
            aflag2 = aflag & (ca == bitA[i])
            for cb in candB:
                if not(ca==cb==1):
                    bflag2 = bflag & (cb == bitB[i])
                    ans += dp(i-1, aflag2, bflag2)
        return ans

    return dp(BIG - 1)


def solve(L, R):
    if L > 0:
        ans = query(R, R)
        ans -= 2 * query(L-1, R)
        ans += query(L-1, L-1)
        return ans
    else:
        return query(R, R)


