def solve(cur_bit,max_bit,d,mod):
    hs = (cur_bit,max_bit)
    if hs in DP: return DP[hs]
    if cur_bit == max_bit: return 1+(d-2**(max_bit-1)+1)
    out = 0
    for nb in range(cur_bit+1,max_bit+1):
        out += pow(2,cur_bit-1,mod)*solve(nb,max_bit,d,mod)
    out %= mod
    DP[hs] = out
    return out

