def dfs(graph, start=0):
    n = len(graph)

    dp = [0] * n
    dp[start] = 1

    visited = [False] * n

    stack = [start]
    while stack:
        start = stack[-1]

        # push unvisited children into stack
        if not visited[start]:
            visited[start] = True
            for child in graph[start]:
                if not visited[child]:
                    dp[child] = dp[start] ^ 3
                    stack.append(child)

        else:
            stack.pop()

    return dp


