def check(k, aas, bs, a_rem, b_rem):
    if a_rem + b_rem < k:
        return False
    a_lo = k - b_rem
    a_hi = a_rem

    rems = set()
    rems.add(0)
    for a, b in zip(aas, bs):
        if a + b < k:
            continue
        for i in range(max(0, k - b), min(a, k) + 1):
            rem = i % k
            for j in list(rems):
                rems.add((j + rem) % k)
    for rem in rems:
        if rem >= a_lo and rem <= a_hi:
            return True
    return False


