    r = n - 1



    # Stores the index of the left most element

    # from the array which is greater than k

    leftGreater = n



    # Finds number of elements greater than k

    while (l <= r):

        m = int(l + (r - l) / 2)

        if (arr[m] >= k):

            leftGreater = m

            r = m - 1



