from types import GeneratorType





def bootstrap(f, stack=[]):

    def wrappedfunc(*args, **kwargs):

        if stack:

            return f(*args, **kwargs)

        else:

            to = f(*args, **kwargs)

            while True:

                if type(to) is GeneratorType:

                    stack.append(to)

                    to = next(to)

                else:

                    stack.pop()

                    if not stack:

                        break

                    to = stack[-1].send(to)

            return to



    return wrappedfunc





farr=[1]

ifa=[]



def fact(x,mod=0):

    if mod:

        while x>=len(farr):

            farr.append(farr[-1]*len(farr)%mod)

    else:

        while x>=len(farr):

            farr.append(farr[-1]*len(farr))

    return farr[x]



def ifact(x,mod):

    global ifa

    ifa.append(pow(farr[-1],mod-2,mod))

    for i in range(x,0,-1):

        ifa.append(ifa[-1]*i%mod)

    ifa=ifa[::-1]



def per(i,j,mod=0):

    if i<j: return 0

    if not mod:

        return fact(i)//fact(i-j)

    return farr[i]*ifa[i-j]%mod



def com(i,j,mod=0):

    if i<j: return 0

    if not mod:        

        return per(i,j)//fact(j)

    return per(i,j,mod)*ifa[j]%mod



def catalan(n):

    return com(2*n,n)//(n+1)



def linc(f,t,l,r):

    while l<r:

        mid=(l+r)//2

        if t>f(mid):

            l=mid+1

        else:

            r=mid

    return l



def rinc(f,t,l,r):

    while l<r:

        mid=(l+r+1)//2

        if t<f(mid):

            r=mid-1

        else:

            l=mid

    return l



