def solve(l, ns):

    idx = [i for i in range(l)]

    idx.sort(key=lambda x: (ns[x], x))  # 稳定排序,先按照nums[i]排序，再按照i排序。

    pst, en = 0, 0  # 前一个值区间的起始位置，当前位置

    res = 0

    c_in = 0 # pst之前可以保留的最多数量

    while en < l:

        cst = en # 当前值的起始位置

        while en < l and ns[idx[en]] == ns[idx[cst]]:

            en += 1

        c_in += cst - pst # 假设前区间可以全部保留

        if cst == 0 or idx[cst] > idx[cst - 1]: #前区间后区间都可以全部保留

            res = max(res, c_in + en - cst)

        else:

            j = en - 1

            # 前一个区间全部保留的基础上，c_in可以通过前区间连接此区间后半部分。

            while j >= cst and idx[j] > idx[cst - 1]:

                c_in += 1

                j -= 1

            res = max(res, c_in)

            #前一个区间不保留完全的情况下c_in不可连接当前区间，可以认为清零了

            i = cst - 1

            te = cst - pst + en - j #前一个区间i及i之前，后一个区间j及j之后的总数量

            while j >= cst:

                while i >= pst and idx[j] < idx[i]:

                    i -= 1 # i坐标太大，变小找到第一个满足大于j的索引，随之维护te

                    te -= 1

                res = max(res, te)

                j -= 1 # j左移，拓展后面区间

                te += 1

            c_in = i - pst + 1 #后区间全部保留，前区间作为第一个区间可选择前半部分连接此区间

        pst = cst

    return l - res



