from collections import Counter, defaultdict, deque

# https://github.com/cheran-senthil/PyRival/blob/master/pyrival/data_structures/SegmentTree.py
class SegmentTree:
    def __init__(self, data, default=0, func=max):
        """initialize the segment tree with data"""
        self._default = default
        self._func = func
        self._len = len(data)
        self._size = _size = 1 << (self._len - 1).bit_length()

        self.data = [default] * (2 * _size)
        self.data[_size : _size + self._len] = data
        for i in reversed(range(_size)):
            self.data[i] = func(self.data[i + i], self.data[i + i + 1])

    def __delitem__(self, idx):
        self[idx] = self._default

    def __getitem__(self, idx):
        return self.data[idx + self._size]

    def __setitem__(self, idx, value):
        idx += self._size
        self.data[idx] = value
        idx >>= 1
        while idx:
            self.data[idx] = self._func(self.data[2 * idx], self.data[2 * idx + 1])
            idx >>= 1

    def __len__(self):
        return self._len

    def query(self, start, stop):
        """func of data[start, stop)"""
        start += self._size
        stop += self._size

        res_left = res_right = self._default
        while start < stop:
            if start & 1:
                res_left = self._func(res_left, self.data[start])
                start += 1
            if stop & 1:
                stop -= 1
                res_right = self._func(self.data[stop], res_right)
            start >>= 1
            stop >>= 1

        return self._func(res_left, res_right)

    def __repr__(self):
        return "SegmentTree({0})".format(self.data)


class Node:
    def __init__(self, count, mn, mx, maxGap):
        self.count = count
        self.mn = mn
        self.mx = mx
        self.maxGap = maxGap


neutral = Node(0, 0, 0, 0)


def combine(x, y):
    if x.count == 0:
        return y
    if y.count == 0:
        return x

    return Node(
        x.count + y.count,
        min(x.mn, y.mn),
        max(y.mx, y.mx),
        max(y.mn - x.mx, x.maxGap, y.maxGap),
    )


def solve(N, Q, P, TX):
    allPoints = sorted(set(P + [x for t, x in TX]))
    compress = {}
    for i, x in enumerate(allPoints):
        compress[x] = i

    counts = [0] * len(allPoints)

    segTree = SegmentTree([neutral] * len(allPoints), neutral, combine)
    for x in P:
        index = compress[x]
        counts[index] += 1
        segTree[index] = Node(counts[index], x, x, 0)

    def query():
        node = segTree.query(0, len(allPoints))
        if node.count == 1:
            return 0
        return node.mx - node.mn - node.maxGap

    ans = [query()]

    for t, x in TX:
        index = compress[x]
        if t == 0:
            counts[index] -= 1
        else:
            counts[index] += 1
            assert t == 1
        segTree[index] = Node(counts[index], x, x, 0)
        ans.append(query())

    return "\n".join(map(str, ans))


