class TreeAncestor:

    def __init__(self, n: int, parent, depth):

        # 根据节点规模设置层数

        self.cols = max(2, math.ceil(math.log2(n)))



        self.dp = [[-1] * self.cols for _ in range(n)]

        for i in range(n):

            self.dp[i][0] = parent[i]

        # 动态规划设置祖先, dp[node][j] 表示 node 往前推第 2^j 个祖先

        for j in range(1, self.cols):

            for i in range(n):

                father = self.dp[i][j-1]

                if father != -1:

                    self.dp[i][j] = self.dp[father][j-1]



        # 计算每个节点的深度

        self.depth = depth

        return



    def get_kth_ancestor(self, node: int, k: int) -> int:

        # 查询节点的第 k 个祖先

        for i in range(self.cols - 1, -1, -1):

            if k & (1 << i):

                node = self.dp[node][i]

                if node == -1:

                    break

        return node



    def get_lca(self, x: int, y: int) -> int:

        if self.depth[x] < self.depth[y]:

            x, y = y, x

        while self.depth[x] > self.depth[y]:

            d = self.depth[x]-self.depth[y]

            x = self.dp[x][int(math.log2(d))]

        if x == y:

            return x

        for k in range(int(math.log2(self.depth[x])), -1, -1):

            if self.dp[x][k] != self.dp[y][k]:

                x = self.dp[x][k]

                y = self.dp[y][k]

        return self.dp[x][0]





