def transform_string1(s):
    r = ''
    c = ''
    i = 1
    while s[i].isdigit():
        r += s[i]
        i += 1
    i += 1
    while i < len(s) and s[i].isdigit():
        c += s[i]
        i += 1
    c = int(c)
    res = ''
    stack = []
    while c:
        if c % 26:
            stack.append(chr(c % 26 + 64))
        elif c == 26:
            stack.append('Z')
            break
        else:
            stack.append('Z')
        c //= 26
    while stack:
        res += stack.pop()
    res += r
    return res

def transform_string2(s):
    stack = []
    i = 0
    while s[i].isdigit() is False:
        stack.append(s[i])
        i += 1
    r = s[i:]
    c = 0
    for j in range(len(stack)):
        c += (ord(stack[j]) - 64) * (26 ** (len(stack) - j - 1))
    res = 'R' + r + 'C' + str(c)
    return res

