from heapq import heappush, heappop


def dijkstra(graph, start):
    dist = dict()
    for v in graph:
        dist[v] = float('inf')
    dist[start] = 0
    q = [(0, start)]
    while q:
        d, v = heappop(q)
        if d > dist[v]:
            continue
        for u, w in graph[v]:
            if dist[v] + w < dist[u]:
                dist[u] = dist[v] + w
                heappush(q, (dist[u], u))
    return dist


