    for value in dists.values():
        if value == l:
            result += 1

    visited = set()
    for key, value in dists.items():
        if value >= l:
            continue
        for u, w in graph[key]:
            if value + w > l and (key, u) not in visited:
                visited.add((key, u))
                result += 1
                delta = value + w - l
                if delta == (value + w) // 2:
                    visited.add((u, key))
            else:
                visited.add((key, u))

    print(result)


