import __pypy__

int_add = __pypy__.intop.int_add
int_sub = __pypy__.intop.int_sub
int_mul = __pypy__.intop.int_mul


def make_mod_mul(mod=10 ** 9 + 7):
    fmod_inv = 1.0 / mod

    def mod_mul(a, b, c=0):
        res = int_sub(
            int_add(int_mul(a, b), c),
            int_mul(mod, int(fmod_inv * a * b + fmod_inv * c)),
        )
        if res >= mod:
            return res - mod
        elif res < 0:
            return res + mod
        else:
            return res

    return mod_mul


mod_mul = make_mod_mul()


def solve(N, K, Q, A, updates):
    MOD = 10 ** 9 + 7
    ans = []

    dp = [[0 for i in range(N)] for j in range(K + 1)]
    for i in range(N):
        dp[0][i] = 1
    for k in range(1, K + 1):
        for i in range(N):
            if i > 0:
                dp[k][i] += dp[k - 1][i - 1]
            if i < N - 1:
                dp[k][i] += dp[k - 1][i + 1]
            dp[k][i] %= MOD

    dp2 = [[0 for i in range(N)] for j in range(K + 1)]

    for k in range(K + 1):
        for i in range(N):
            dp2[k][i] = mod_mul(dp[k][i], dp[K - k][i], dp2[k][i])

    dp3 = [0] * N
    for k in range(K + 1):
        for i in range(N):
            dp3[i] += dp2[k][i]
            dp3[i] %= MOD
    score = 0
    for i in range(N):
        score = mod_mul(A[i], dp3[i], score)

    for i, x in updates:
        i -= 1  # 0 indexed
        score = mod_mul(-A[i], dp3[i], score)
        A[i] = x
        score = mod_mul(A[i], dp3[i], score)
        ans.append(score)
    return "\n".join(map(str, ans))


