class LazySegmentTree:
    def __init__(self, data, default=0, func=max):
        """initialize the lazy segment tree with data"""
        _default = default
        self._func = func

        self._len = len(data)
        self._size = _size = 1 << (self._len - 1).bit_length()
        self._lazy = [0] * (2 * _size)

        self.data = [default] * (2 * _size)
        self.data[_size : _size + self._len] = data
        for i in reversed(range(_size)):
            self.data[i] = func(self.data[i + i], self.data[i + i + 1])

    def __len__(self):
        return self._len

    def _push(self, idx):
        """push query on idx to its children"""
        # Let the children know of the queries
        q, self._lazy[idx] = self._lazy[idx], 0

        self._lazy[2 * idx] += q
        self._lazy[2 * idx + 1] += q
        self.data[2 * idx] += q
        self.data[2 * idx + 1] += q

    def _update(self, idx):
        """updates the node idx to know of all queries applied to it via its ancestors"""
        for i in reversed(range(1, idx.bit_length())):
            self._push(idx >> i)

    def _build(self, idx):
        """make the changes to idx be known to its ancestors"""
        idx >>= 1
        while idx:
            self.data[idx] = (
                self._func(self.data[2 * idx], self.data[2 * idx + 1]) + self._lazy[idx]
            )
            idx >>= 1

    def add(self, start, stop, value):
        """lazily add value to [start, stop)"""
        if start == stop:
            return
        start = start_copy = start + self._size
        stop = stop_copy = stop + self._size
        while start < stop:
            if start & 1:
                self._lazy[start] += value
                self.data[start] += value
                start += 1
            if stop & 1:
                stop -= 1
                self._lazy[stop] += value
                self.data[stop] += value
            start >>= 1
            stop >>= 1

        # Tell all nodes above of the updated area of the updates
        self._build(start_copy)
        self._build(stop_copy - 1)

    def query(self, start, stop, default=0):
        """func of data[start, stop)"""
        start += self._size
        stop += self._size

        # Apply all the lazily stored queries
        self._update(start)
        self._update(stop - 1)

        res = default
        while start < stop:
            if start & 1:
                res = self._func(res, self.data[start])
                start += 1
            if stop & 1:
                stop -= 1
                res = self._func(res, self.data[stop])
            start >>= 1
            stop >>= 1
        return res

    def __repr__(self):
        return "LazySegmentTree({0})".format(self.data)


def solve(N, A, edges):

    graph = [[] for i in range(N)]
    for u, indices in edges:
        graph[u].append(indices)
        graph[indices].append(u)

    # Build euler tour
    eulerTour = []
    root = 0
    stack = [root]
    seen = [False] * len(graph)
    while stack:
        node = stack.pop()
        eulerTour.append(node)
        if not seen[node]:
            seen[node] = True
            for nbr in graph[node]:
                if not seen[nbr]:
                    stack.append(node)
                    stack.append(nbr)

    assert eulerTour[0] == eulerTour[-1]
    eulerTour.pop()

    # Group the tour by values
    tourByValues = defaultdict(list)
    for i, x in enumerate(eulerTour):
        tourByValues[A[x]].append(i)

    # Track which part of the tour definitely can't be root (0 is good, positive is bad)
    segTree = LazySegmentTree([0] * len(eulerTour), 0, lambda x, y: x + y)

    for k, indices in tourByValues.items():
        nodes = set(eulerTour[i] for i in indices)
        if len(nodes) >= 2:
            # Dupes can't be root
            for i in indices:
                segTree.add(i, i + 1, 1)

            # Get tour of the subtree with same values
            # If adjacent are the same, is actually visiting outside of the subtree (all of which can't be root)
            # Otherwise is part of the subtour
            subtour = []
            for i, j in zip(indices, indices[1:]):
                x = eulerTour[i]
                y = eulerTour[j]
                if x == y:
                    segTree.add(i, j + 1, 1)
                else:
                    subtour.append(i)
            i = indices[-1]
            j = indices[0]
            x = eulerTour[i]
            y = eulerTour[j]
            if x == y:
                segTree.add(i, len(eulerTour), 1)
                segTree.add(0, j + 1, 1)
            else:
                subtour.append(i)

            if len(nodes) != len(subtour):
                # Subtour has non leaves, impossible
                return 0
        if False:
            print("label", k, "visits", indices, "nodes", nodes)
            print(
                "\t".join(
                    str(eulerTour[i]) + ":" + str(A[eulerTour[i]])
                    for i in range(len(eulerTour))
                )
            )
            for i in range(len(eulerTour)):
                if segTree.query(i, i + 1) != 0:
                    print("x", end="\t")
                else:
                    print("o", end="\t")
            print()
            print()
    ans = set()
    for i in range(len(eulerTour)):
        if segTree.query(i, i + 1) != 0:
            ans.add(eulerTour[i])

    return N - len(set(ans))


