def solve(arr, k):
    n_rounds = []
    for i in arr:
        p = 0
        while i % k**(p+1) == 0:
            p += 1
        n_rounds.append(p)
    worst = min(n_rounds)
    last_good = n_rounds.index(worst)
    return sum(arr) * (worst+1) + sum(arr[:last_good])

