inf = float('inf')

CACHE = dict()

class RMQ:

    def __init__(self, nums):        

        self.nums = nums

        self.dp = self.sparse(nums)

        self.n = len(nums)

        self._cache = [-1]*(1 + len(nums))



    def sparse(self, a):

        n = len(a)

        # dp[i][k] = min(a[i], a[i+1],... a[i + (1<<k) - 1])

        # dp[i][k] = min(dp[i][k-1], dp[i + (1<<(k-1))][k-1])

        sz = 0

        while (1<<sz) <= n:

            sz += 1



        dp = [[inf]*(1+sz) for _ in range(n)]

        for k in range(1+sz):

            for i in range(n):

                if k == 0:

                    dp[i][k] = a[i]

                    continue



                if i + (1<<k) - 1 >= n:

                    continue



                dp[i][k] = min(dp[i][k-1], dp[i + (1<<(k-1))][k-1])



        return dp    



    def find_k(self, l):

        if self._cache[l] != -1:

            return self._cache[l]



        k = 0

        while (1<<(k+1)) <= l:

            k += 1



        self._cache[l] = k

        return k



    def query(self, l, r):

        if r<l:

            return inf

        dp = self.dp

        k = self.find_k(r-l)



        return min(dp[l][k], dp[r - (1<<k) + 1][k])



    def locate(self, i):

        return self.nums[i]



