def solve(N, M, edges):
    graph = [[] for i in range(N)]
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def bfs(source):
        q = deque([source])
        dist = [-1] * N
        dist[source] = 0
        while q:
            node = q.popleft()
            d = dist[node]
            for nbr in graph[node]:
                if dist[nbr] == -1:
                    q.append(nbr)
                    dist[nbr] = d + 1
        return dist

    dists = [bfs(u) for u in range(N)]

    MOD = 998244353
    ans = [[0 for i in range(N)] for j in range(N)]
    for x in range(N):
        for y in range(x, N):
            onPath = 0
            for i in range(N):
                if dists[x][i] + dists[y][i] == dists[x][y]:
                    onPath += 1
            numVertices = dists[x][y] + 1  # including x and y
            ways = 1
            if onPath > numVertices:
                ways = 0
            else:
                for i in range(N):
                    if dists[x][i] + dists[y][i] != dists[x][y]:
                        count = 0
                        for j in graph[i]:
                            if (
                                dists[x][i] == dists[x][j] + 1
                                and dists[y][i] == dists[y][j] + 1
                            ):
                                count += 1
                        ways = (ways * count) % MOD
                        if not ways:
                            break
            ans[x][y] = ways
            ans[y][x] = ways

    return "\n".join(" ".join(map(str, row)) for row in ans)


