def cat(n, k):
    if n % 2 == 0:
        mod = k % n
        if mod == 0: mod = n
        return mod
    # odd
    if k == 1:
        return 1
    cycle_length = (n - 1) // 2
    ncycles = (k - 1) // cycle_length
    res = (k - 1) % cycle_length

    mod = (1 + (ncycles * (n + 1) // 2) + res) % n
    if mod == 0: mod = n
    return mod

