class Graph:
    def __init__(self, n_vertices, edges, directed=True):
        self.n_vertices = n_vertices
        self.directed = directed
        self.edges = edges

    @property
    def adj(self):
        try:
            return self._adj
        except AttributeError:
            adj = [[] for _ in range(self.n_vertices)]
            if self.directed:
                for u,v in self.edges:
                    adj[u].append(v)
            else:
                for u,v in self.edges:
                    adj[u].append(v)
                    adj[v].append(u)
            self._adj = adj
            return adj


class RootedTree(Graph):
    def __init__(self, n_vertices, edges, root_vertex=0):
        """
        mode:
            'rerooting' -> initialize just enough to do rerooting dp
        """
        super().__init__(n_vertices, edges, directed=False)
        self.root = root_vertex


    @property
    def parent(self):
        try:
            return self._parent
        except AttributeError:
            adj = self.adj
            parent = [0]*self.n_vertices
            parent[self.root] = -1
            stack = [self.root]
            for _ in range(self.n_vertices):
                v = stack.pop()
                p = parent[v]
                for u in adj[v]:
                    if u != p:
                        parent[u] = v
                        stack.append(u)
            self._parent = parent
            return parent

    @property
    def children(self):
        try:
            return self._children
        except AttributeError:
            children = [None]*self.n_vertices
            for v,(l,p) in enumerate(zip(self.adj,self.parent)):
                children[v] = [u for u in l if u != p]
            self._children = children
            return children

    @property
    def dfs_order(self):
        try:
            return self._dfs_order
        except AttributeError:
            order = [0]*self.n_vertices
            children = self.children
            stack = [self.root]
            for i in range(self.n_vertices):
                v = stack.pop()
                order[i] = v
                for u in children[v]:
                    stack.append(u)
            self._dfs_order = order
            return order

def solve(edges, n):
    fib = [1,1]
    while fib[-1] < n:
        fib.append(fib[-1]+fib[-2])
    if fib[-1] != n:
        return False
    rt = RootedTree(n, edges)
    parent = rt.parent
    children = rt.children
    size = [0]*n

    stack = [(len(fib)-1, 0)]
    while stack:
        ind, root = stack.pop()
        if ind <= 1:
            continue
        split = [fib[ind-2],fib[ind-1]]

        s = [~root, root]
        while s:
            v = s.pop()
            if v < 0:
                v = ~v
                t = 1+sum(size[u] for u in children[v])
                size[v] = t
                p = parent[v]
                if t in split:
                    if t == split[0]:
                        stack.append((ind-2, v))
                        stack.append((ind-1, root))
                    else:
                        stack.append((ind-1, v))
                        stack.append((ind-2, root))
                    children[p].remove(v)
                    parent[v] = -1
                    break
            else:
                for u in children[v]:
                    s.append(~u)
                    s.append(u)
        else:
            return False
    return True


