def henkan(s, radix):
    res = 0
    for c in s:
        res *= radix
        if 48 <= ord(c) <= 57:
            if ord(c) - ord('0') >= radix:
                return -1
            res += int(c)
        elif 65 <= ord(c) <= 90:
            if ord(c) - ord('A') + 10 >= radix:
                return -1
            res += ord(c) - ord('A') + 10       
    return res

