from heapq import heappop, heappush

inf = float("inf")


def dijkstra(source, N, getAdj):

    dist = [inf] * N
    dist[source] = 0.0
    queue = [(0.0, float(source))]
    while queue:
        d, u = heappop(queue)
        u = int(u)
        if dist[u] == d:
            for v, w in getAdj(u):
                cost = d + w
                if cost < dist[v]:
                    dist[v] = cost
                    heappush(queue, (cost, float(v)))
    return dist


def solve(N, M, edges):

    graph = [[] for i in range(N)]
    for u, v, w in edges:
        u -= 1
        v -= 1
        graph[u].append((v, w))
        graph[v].append((u, w))

    def getAdj(u):
        ret = []
        for v1, w1 in graph[u]:
            for v2, w2 in graph[v1]:
                ret.append((v2, (w1 + w2) * (w1 + w2)))
        return ret

    dist = dijkstra(0, N, getAdj)

    for i, x in enumerate(dist):
        if x == inf:
            dist[i] = -1
        else:
            dist[i] = int(dist[i])
    return " ".join(map(str, dist))


