def solve(N, A):
    A = sorted(A)
    best_dict = {0: A[N-1]-A[0]}

    for i in range(N-1):
        best_dict_copy = {}
        for my_key in best_dict.keys():
            #either take beginning or end
            cur_val = best_dict[my_key]
            next_val_1 = cur_val + A[my_key+N-2-i] - A[my_key]
            next_val_2 = cur_val + A[my_key+N-1-i] - A[my_key+1]
            best_dict_copy[my_key] = min(next_val_1, best_dict_copy.get(my_key, 2000 * 10 ** 9))
            best_dict_copy[my_key+1] = min(next_val_2, best_dict_copy.get(my_key+1, 2000 * 10 ** 9))
        best_dict = best_dict_copy
    return min(best_dict.values())



