using namespace std;

int dp[1 << 8][210];
int dist[210][210];
int inter[210][210];
int mark[210];
int a[210];

const int INF = int(1e9);

void take_path(int u, int v){
    mark[u] = mark[v] = 1;
    if(u == v || inter[u][v] == u || inter[u][v] == v){
        return;
    }

    take_path(u, inter[u][v]);
    take_path(inter[u][v], v);
}

void dfs(int i, int j){
    mark[j] = 1;
    if(i != 0){
        bool taked = false;

        for(int s = (i - 1) & i ; s ; s = (s - 1) & i){
            if(dp[i][j] == dp[s][j] + dp[i ^ s][j] - a[j]){
                dfs(s, j);
                dfs(i ^ s, j);
                taked = true;
                break;
            }
        }

        if(taked){
            return;
        }
    }

    for(int u = 0 ; u < j ; u++){
        if(dp[i][j] == dp[i][u] + dist[u][j] - a[u]){
            take_path(u, j);
            dfs(i, u);
            break;
        }
    }
}

int main(){
    int n, m, k;
    cin >> n >> m >> k;

    for(int i = 0 ; i < n ; i++){
        for(int j = 0 ; j < m ; j++){
            int aij;
            cin >> aij;
            a[i * m + j] = aij;
        }
    }

    for(int i = 0 ; i < n * m ; i++){
        int l = i / m;
        int c = i % m;

        for(int j = 0 ; j < n * m ; j++){
            int lj = j / m;
            int cj = j % m;

            if(abs(l - lj) + abs(c - cj) <= 1){
                dist[i][j] = a[i] + a[j];
                inter[i][j] = i;
            }else{
                dist[i][j] = INF;
            }
        }

        dist[i][i] = a[i];
    }

    for(int k = 0 ; k < n * m ; k++){
        for(int i = 0 ; i < n * m ; i++){
            for(int j = 0 ; j < n * m ; j++){
                auto cdis = dist[i][k] + dist[k][j] - a[k];

                if(cdis < dist[i][j]){
                    dist[i][j] = cdis;
                    inter[i][j] = k;
                }
            }
        }
    }

    for(int i = 0 ; i < k ; i++){
        int x, y;

        cin >> x >> y;
        x--, y--;
        int id = x * m + y;

        dp[1 << i][id] = a[id]; 
    }

    for(int i = 0 ; i < (1 << k) ; i++){
        for(int j = 0 ; j < n * m ; j++){
            if(dp[i][j] != 0) continue;

            if(i == 0){
                dp[i][j] = a[j];
            }else{
                dp[i][j] = INF;
            }

            if(i != 0){
                for(int s = (i - 1) & i ; s ; s = (s - 1) & i){
                    dp[i][j] = min(dp[i][j], dp[s][j] + dp[i ^ s][j] - a[j]);
                }
            }

            for(int u = 0 ; u < j ; u++){
                dp[i][j] = min(dp[i][j], dp[i][u] + dist[u][j] - a[u]);
            }
        }
    }

    int mn = INF;
    int mn_pos = -1;

    for(int j = 0 ; j < n * m ; j++){
        if(dp[(1 << k) - 1][j] < mn){
            mn = dp[(1 << k) - 1][j];
            mn_pos = j;
        }
    }

    cout << mn << endl;

