def solve(inp, out):
  # type: (Input, Output) -> any
  n, m = map(int, inp.rawInput().split())

  path_lens = []  # type: List[deque[int]]
  run_on = [[] for _ in range(n)]

  for _ in range(n):
    lens = map(int, inp.rawInput().split())
    lens.sort()
    path_lens.append(deque(lens))

  for _ in range(m):
    min_idx = min(range(n), key=lambda x: path_lens[x][0])
    for i in range(n):
      if i == min_idx:
        t = path_lens[i].popleft()
      else:
        t = path_lens[i].pop()
      run_on[i].append(t)

  for ro in run_on:
    out.writeLine(' '.join(map(str, ro)))


