"""
Given a directed graph, find_SCC returns a list of lists containing 
the strongly connected components in topological order.
Note that this implementation can be also be used to check if a directed graph is a
DAG, and in that case it can be used to find the topological ordering of the nodes.
"""

def find_SCC(graph):
    SCC, S, P = [], [], []
    depth = [0] * len(graph)

    stack = list(range(len(graph)))
    while stack:
        node = stack.pop()
        if node < 0:
            d = depth[~node] - 1
            if P[-1] > d:
                SCC.append(S[d:])
                del S[d:], P[-1]
                for node in SCC[-1]:
                    depth[node] = -1
        elif depth[node] > 0:
            while P[-1] > depth[node]:
                P.pop()
        elif depth[node] == 0:
            S.append(node)
            P.append(len(S))
            depth[node] = len(S)
            stack.append(~node)
            stack += graph[node]
    return SCC[::-1]

def main():
    from math import gcd
    n,m = map(int,input().split())
    graph = []
    graphSCC = []
    for _ in range(n):
        graph.append([])
        graphSCC.append([])
    for _ in range(m):
        a,b,l = map(int,input().split())
        graphSCC[a - 1].append(b - 1)
        graph[a - 1].append((b - 1, l))
    scc = find_SCC(graphSCC)
    sccNum = [0] * n
    for i in range(len(scc)):
        for elem in scc[i]:
            sccNum[elem] = i
    weight = [-1] * n
    gcdd = [0] * len(scc)
    for i in range(len(scc)):
        stack = [scc[i][0]]
        weight[scc[i][0]] = 0
        while stack:
            cur = stack.pop()
            for elem in graph[cur]:
                if sccNum[elem[0]] != i:
                    continue
                if weight[elem[0]] == -1:
                    stack.append(elem[0])
                    weight[elem[0]] = weight[cur] + elem[1]
                else:
                    gcdd[i] = gcd(gcdd[i], - weight[elem[0]] + weight[cur] + elem[1])
    q = int(input())
    for _ in range(q):
        v,s,t = map(int,input().split())
        if s % gcd(gcdd[sccNum[v - 1]], t):
            print("NO")
        else:
            print("YES")




# region fastio

BUFSIZE = 8192


class FastIO(IOBase):
    newlines = 0

    def __init__(self, file):
        self._fd = file.fileno()
        self.buffer = BytesIO()
        self.writable = "x" in file.mode or "r" not in file.mode
        self.write = self.buffer.write if self.writable else None

    def read(self):
        while True:
            b = os.read(self._fd, max(os.fstat(self._fd).st_size, BUFSIZE))
            if not b:
                break
            ptr = self.buffer.tell()
            self.buffer.seek(0, 2), self.buffer.write(b), self.buffer.seek(ptr)
        self.newlines = 0
        return self.buffer.read()

    def readline(self):
        while self.newlines == 0:
            b = os.read(self._fd, max(os.fstat(self._fd).st_size, BUFSIZE))
            self.newlines = b.count(b"\n") + (not b)
            ptr = self.buffer.tell()
            self.buffer.seek(0, 2), self.buffer.write(b), self.buffer.seek(ptr)
        self.newlines -= 1
        return self.buffer.readline()

    def flush(self):
        if self.writable:
            os.write(self._fd, self.buffer.getvalue())
            self.buffer.truncate(0), self.buffer.seek(0)


class IOWrapper(IOBase):
    def __init__(self, file):
        self.buffer = FastIO(file)
        self.flush = self.buffer.flush
        self.writable = self.buffer.writable
        self.write = lambda s: self.buffer.write(s.encode("ascii"))
        self.read = lambda: self.buffer.read().decode("ascii")
        self.readline = lambda: self.buffer.readline().decode("ascii")


