def euclid_sieve(n):
    lp = (n+1) * [0]
    primes = []
    i = 2
    while i <= n:
        if lp[i] == 0:
            primes.append(i)
            lp[i] = i
        for p in primes:
            if p > lp[i] or i*p > n:
                break
            lp[i*p] = p
        i += 1
    return lp

