def solve(N,A):
    diff = [A[i+1]-A[i] for i in range(N-1)]

    GCD = SparseTable(diff,gcd,0)

    def cond(k):
        for i in range(N-k+1):
            check = GCD.query(i,i+k-2)
            if check > 1:
                return True
        return False

    ok = 1
    ng = N+1
    while ng-ok>1:
        mid = (ok+ng)//2
        if cond(mid):
            ok = mid
        else:
            ng = mid
    return ok


