from sys import stdin
from itertools import repeat
def f(x, y, z):
    return x < y > z or x > y < z
def solve():
    n = int(stdin.readline())
    a = map(int, stdin.readline().split(), repeat(10, n))
    if n == 1:
        print 1
        return
    ans = 2 * n - 1
    for i in xrange(n - 2):
        x, y, z = a[i:i+3]
        if f(x, y, z):
            ans += 1
            if i < n - 3 and f(x, y, a[i+3]) and f(x, z, a[i+3]) and f(y, z, a[i+3]):
                ans += 1
    print ans

T = int(stdin.readline())
