    solve()

mod = 1000000007
f = [1] * 200001
for i in xrange(2, 200001):
    f[i] = f[i-1] * i % mod
invf = [1] * 200001
invf[-1] = pow(f[-1], mod - 2, mod)
for i in xrange(200000, 2, -1):
    invf[i-1] = invf[i] * i % mod
def C(n, k):
    if k < 0 or k > n:
        return 0
    return f[n] * invf[k] * invf[n-k] % mod
def solve(mn=min, mx=max):
    n, l, r = map(int, raw_input().split())
    p = min(r - n, 1 - l)
    ans = C(n, n / 2) * p % mod
    if n % 2:
        ans = ans * 2 % mod
    while 1:
        p += 1
        u = n - mn(n, r - p)
        d = mx(l + p, 1) - 1
        if u + d > n:
            break
        ans += C(n - u - d, n / 2 - u)
        if n % 2:
            ans += C(n - u - d, n - n / 2 - u)
        ans %= mod
    print ans

T = int(raw_input())
for t in xrange(T):
    solve()
